const sortByData = $items("LIMIT");
const previousNodeData = $input.all();

// Get steam_tags from Retrieve One Tag Only
const steamTagsRaw = sortByData.map(item => item.json.steam_tags);

// Normalize steam tags for comparison
const steamTags = new Set(
  steamTagsRaw
    .map(tag => tag?.toLowerCase().trim())
    .filter(Boolean)
);

// Match against previous node (Steam tag list)
const matched = previousNodeData.filter(item => {
  const name = item.json.name?.toLowerCase().trim();
  return steamTags.has(name);
});

// Remove duplicates by tagid
const unique = [];
const seen = new Set();

for (const item of matched) {
  if (!seen.has(item.json.tagid)) {
    seen.add(item.json.tagid);
    unique.push(item);
  }
}

// ✅ If matches found → return them
if (unique.length > 0) {
  return unique.map(item => ({
    json: item.json
  }));
}

// ❗ If NO matches → return original steam_tags with note
return steamTagsRaw.map(tag => ({
  json: {
    steam_tags: tag,
    notes: "no matching tags were found in SteamDB. please inform Justin  about this."
  }
}));

return items.map(item => {

  const name = item.json.name?.trim();

  // Extract appid from logo URL (after "apps/")
  const logo = item.json.logo || "";
  const match = logo.match(/apps\/(\d+)/);
  const appid = match ? match[1] : null;

  return {
    json: {
      name,
      appid
    }
  };
});

const results = [];

for (const item of $input.all()) {
  const rawData = item.json;

  for (const appId in rawData) {
    const entry = rawData[appId];

    if (entry.success && entry.data) {
      const { name, steam_appid, developers, publishers } = entry.data;
      results.push({
        game_name: name,
        appid: steam_appid,
        publisher_name: publishers ? publishers.join(', ') : null,
        developer_name: developers ? developers.join(', ') : null,
      });
    }
  }
}

return results.map(item => ({ json: item }));

// Get data from the node named "Wait: User Tag"
const userTagData = $items("HR: WAIT - USER TAG");

// Extract the JSON data
const tags = userTagData.map(item => item.json);

// Return it (or modify as needed)
return tags.map(tag => ({
  json: {
    tag_id: tag.tagid,
    tag_name: tag.name
  }
}));

return items.map(item => {

  const d = item.json;

  // Convert visibility
  let visibilityText = null;

  if (d.visibility === 0) {
    visibilityText = "Yes";
  } else if (d.visibility === 1) {
    visibilityText = "No";
  }

  return {
    json: {
      product_id: d.id ?? null,
      madmin_game_name: d.name ?? null,
      visibility: visibilityText,
      status: d.id ? null : "game name is not found in madmin",
      madmin_link: d.id
        ? `https://madmin.keymailer.co/catalogue/products/${d.id}`
        : null
    }
  };

});

const segmentMap = {
  1: "Indie",
  2: "Studio",
  4: "Publisher",
  5: "Enterprise",
  6: "Quote Only"
};

return items.map(item => {
  const data = item.json;

  const hasOrganisation = data.organisation_id !== null && data.organisation_id !== undefined;

  // Map segment
  const segmentText = segmentMap[data.segment_id] || null;

  // Build base output
  let output = {
    product_name: data.product_name,
    publisher_status: data.status
  };

  // If organisation exists → return full mapped data
  if (hasOrganisation) {
    output = {
      product_name: data.product_name,
      madmin_publisher_id: data.organisation_id,
      madmin_publisher_name: data.organisation_name,
      madmin_publisher_link: data.organisation_id
        ? `https://madmin.keymailer.co/publishers/${data.organisation_id}`
        : null,
      segment: segmentText,
      contact_count: data.contact_count,
      publisher_status: data.status
    };
  }

  return {
    json: output
  };
});

// Get data from each node
const tagItems = $("HR: WAIT - USER TAG").all();
const loopItems = $("LOOP V2").all();
const madminItems = $("HR: FORMAT MADMIN OUTPUT V1").all();
const prevItems = items; // previous node (publisher check) output

// Extract tag name
const tagName = tagItems[0]?.json?.name || "";

// Build lookup maps
const madminMap = {};
for (const item of madminItems) {
  const key = item.json.madmin_game_name?.toLowerCase().trim();
  if (key) madminMap[key] = item.json;
}

const publisherMap = {};
for (const item of prevItems) {
  const key = item.json.product_name?.toLowerCase().trim();
  if (key) publisherMap[key] = item.json;
}

const results = [];

for (const loopItem of loopItems) {
  const gameName = loopItem.json.game_name;
  const gameNameKey = gameName?.toLowerCase().trim();

  const madminRecord = madminMap[gameNameKey] || {};
  const publisherRecord = publisherMap[gameNameKey] || {};

  // Build automation_notes
  const notes = [];
  if (madminRecord.status != null && madminRecord.status !== "") {
    notes.push(madminRecord.status);
  }
  if (publisherRecord.publisher_status === "no active organisation found") {
    notes.push("no active organisation found");
  }
  const automation_notes = notes.join(", ") || null;

  results.push({
    json: {
      tags: tagName,
      steam_game_name: gameName,
      steam_game_name_link: `https://store.steampowered.com/app/${loopItem.json.appid}`,
      steam_publisher_name: loopItem.json.publisher_name,
      steam_developer_name: loopItem.json.developer_name,
      madmin_game_name: madminRecord.madmin_game_name || null,
      madmin_product_link: madminRecord.madmin_link || null,
      is_product_hidden: madminRecord.visibility || null,
      madmin_publisher_name: publisherRecord.madmin_publisher_name || null,
      madmin_publisher_link: publisherRecord.madmin_publisher_link || null,
      segment: publisherRecord.segment || null,
      contact_count: publisherRecord.contact_count || null,
      automation_notes: automation_notes,
    }
  });
}

return results;

// Get all items from the previous previous node
const previousData = $items("HR: FORMAT THE MADMIN OUTPUT V2") || [];

// Filter and map only items that have madmin_publisher_id
const result = previousData
  .map(item => item.json)
  .filter(item => item.madmin_publisher_id) // Skip if no ID
  .map(item => ({
    json: {
      madmin_publisher_id: item.madmin_publisher_id,
      madmin_publisher_name: item.madmin_publisher_name
    }
  }));

return result;
